// Generic function with type parameter T
// T is a placeholder — it will be replaced with the actual type at call time
function getFirstElement<T>(array: T[]): T | undefined {
  // If the array is not empty, return the first element
  if (array.length > 0) {
    return array[0];
  }
  // Return undefined for empty arrays
  return undefined;
}
// TypeScript infers T as string from the argument
const firstString: string | undefined = getFirstElement(['a', 'b', 'c']);
// TypeScript infers T as number
const firstNumber: number | undefined = getFirstElement([10, 20, 30]);
// TypeScript infers T as a custom object type
const firstProduct = getFirstElement([
  { id: 1, name: 'Laptop' },
  { id: 2, name: 'Mouse' },
]);
console.log(firstString, firstNumber, firstProduct?.name);
// Expected: a 10 Laptop
